mapper.select:
/* getMenuList */ SELECT CONCAT(MENUKEY,MNHDKEY) as ROWKEY, MENUKEY, MNHDKEY, MENUFID, MENUGBN, MENUNAM, MENUSEQ, MENULKY, PROGRID, PRGMURL, MNUSEYN, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER, UPDTCHK FROM ${schema}.SMNUMA WHERE MENUFID = #{param.menufid} AND MNHDKEY = #{param.mnhdkey} AND MNUSEYN = 'Y'
AND MNHDKEY = #{param.mnhdkey}
AND MENUFID = #{param.menufid}
ORDER BY LPAD(MENUSEQ, 5, '0')

mapper.update:
/* updateSmnuma */ UPDATE ${userData.schema}.SMNUMA SET MNHDKEY = #{param.mnhdkey}, PROGRID = #{param.progrid}, MENUNAM = #{param.menunam}, MENUSEQ = #{param.menuseq}, MNUSEYN = #{param.mnuseyn}, MENULKY = #{param.menulky},
PRGMURL = #{param.prgmurl},
LMODATE = date_format(now(), '%Y%m%d'), LMOTIME = date_format(now(), '%H%i%s'), LMOUSER = #{userData.useract}, UPDTCHK = #{param.updtchk} + 1 WHERE MENUKEY = #{param.menukey} AND UPDTCHK = #{param.updtchk}

