/* getRoleList */ SELECT ROLGKEY as ROWKEY , ROLGKEY, ROLGKEY as OLDRLKY, ROLGNAM , ROLDESC , CNFRMYN, RLUSEYN, CREDATE, CRETIME , CREUSER , LMODATE, LMOTIME, LMOUSER , UPDTCHK FROM ${schema}.SROLGR WHERE RLUSEYN = 'Y'
AND ROLGNAM LIKE CONCAT('%', #{param.rolgnam}, '%')
AND CNFRMYN = #{param.cnfrmyn}

