/* saveMenuByRole */
INSERT INTO ${userData.schema}.SROLMN
(
	ROLNMKY
	, ROLGKEY
	, MENUKEY
	, RMUSEYN
	, CREDATE
	, CRETIME
	, CREUSER
	, LMODATE
	, LMOTIME
	, LMOUSER
)
VALUES
(
	#{param.rolnmky}
	, #{param.rolgkey}
	, #{param.menukey}
	, #{param.rmuseyn}
	, date_format(now(), '%Y%m%d')
	, date_format(now(), '%H%i%s')
	, #{userData.useract}
	, date_format(now(), '%Y%m%d')
	, date_format(now(), '%H%i%s')
	, #{userData.useract}
)
ON DUPLICATE KEY UPDATE
	RMUSEYN = #{param.rmuseyn}
	, UPDTCHK = #{param.updtchk} + 1

mapper.select:
/* selectAppUserList */ SELECT CONCAT(USERKEY, USERACT) AS ROWKEY , USERKEY, USERACT, USERNAM, TELPHNM , USRMEMO, EMAILAD , DATE_FORMAT(CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(CREUSER) AS CREUSER , DATE_FORMAT(LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(LMOUSER) AS LMOUSER FROM ${userData.commonSchema}.SUSRMA
AND USERACT LIKE CONCAT('%', UPPER(#{param.useract}), '%')
AND USERNAM LIKE CONCAT('%', UPPER(#{param.usernam}), '%')
AND ACTIVYN = #{param.activyn} AND APUSEYN = #{param.apuseyn}

/* selectVehicleByUser */ SELECT CONCAT(SU.USERKEY, SU.VEHICKY) AS ROWKEY , SU.VEHICKY as OLDVEKY , SU.USERKEY, SU.USERACT, SU.VEHICKY, MV.VHCSNAM, MV.VHCFNAM , MC1.COMCDTX AS DLVTYPE, MC2.COMCDTX AS VHCOPTY, MC3.COMCDTX AS VHCTYPE, MC4.COMCDTX AS VHCSTAT , MC5.COMCDTX AS VHCTNCD, MV.VHCMAXW, MV.VHCCAPA, MV.DRVERNM , MV.DRVERPH, MV.INBVHYN, MV.OUBVHYN, MV.POSCOYN , MV.VHCVRYN, SU.VHUSEYN, MO.VOWNKEY, MO.VONAMLC, MO.VOWNKEY as OLDVOKY , DATE_FORMAT(SU.CREDATE,'%Y-%m-%d') AS CREDATE , DATE_FORMAT(STR_TO_DATE(SU.CRETIME,'%H%i%s'),'%H:%i:%s') AS CRETIME , ${userData.schema}.FN_SY_USERNAM(SU.CREUSER) AS CREUSER , DATE_FORMAT(SU.LMODATE,'%Y-%m-%d') AS LMODATE , DATE_FORMAT(STR_TO_DATE(SU.LMOTIME,'%H%i%s'),'%H:%i:%s') AS LMOTIME , ${userData.schema}.FN_SY_USERNAM(SU.LMOUSER) AS LMOUSER, SU.UPDTCHK FROM ${userData.commonSchema}.SUSRVH SU INNER JOIN ${userData.commonSchema}.SUSRMA SUS ON SU.USERKEY = SUS.USERKEY AND SU.USERACT = SUS.USERACT INNER JOIN ${userData.commonSchema}.MVHCMA MV ON SU.VEHICKY = MV.VEHICKY INNER JOIN ${userData.commonSchema}.MVOWMA MO ON MV.VOWNKEY = MO.VOWNKEY INNER JOIN ${userData.schema}.MCODEM MC1 ON MC1.COMCDKY = 'DLVTYPE' AND MC1.COMCDVL = MV.DLVTYPE INNER JOIN ${userData.schema}.MCODEM MC2 ON MC2.COMCDKY = 'VHCOPTY' AND MC2.COMCDVL = MV.VHCOPTY INNER JOIN ${userData.schema}.MCODEM MC3 ON MC3.COMCDKY = 'VHCTYPE' AND MC3.COMCDVL = MV.VHCTYPE INNER JOIN ${userData.schema}.MCODEM MC4 ON MC4.COMCDKY = 'VHCSTAT' AND MC4.COMCDVL = MV.VHCSTAT INNER JOIN ${userData.schema}.MCODEM MC5 ON MC5.COMCDKY = 'VHCTNCD' AND MC5.COMCDVL = MV.VHCTNCD
SUS.ACTIVYN = #{param.activyn} AND MV.VHUSEYN = 'Y' AND SU.USERACT = #{param.useract}
AND SU.USERKEY LIKE CONCAT('%', UPPER(#{param.userkey}), '%')
AND (MV.PUBLCYN = 'Y' OR (MV.PUBLCYN = 'N' AND MV.DMWPLNM = #{param.subDomain}))
AND (MV.PUBLCYN = 'Y' OR (MV.PUBLCYN = 'N' AND MV.DMWPLNM = REPLACE(LOWER(#{userData.schema}), '_', '-')))
ORDER BY MO.VOWNKEY, SU.VEHICKY

