/* syu05UpdateDriver */
UPDATE ${userData.commonSchema}.SUSRVH
	SET VEHICKY = #{param.vehicky}
		, VOWNKEY = #{param.vownkey}
		, VHUSEYN = #{param.vhuseyn}
		, LMODATE = DATE_FORMAT(NOW(), '%Y%m%d')
		, LMOTIME = DATE_FORMAT(NOW(), '%H%i%s')
		, LMOUSER = #{userData.useract}
		, UPDTCHK = #{param.updtchk} + 1
	WHERE
		USERKEY = #{param.userkey}
		AND USERACT = #{param.useract}
		AND VEHICKY = #{param.oldveky}
		AND VOWNKEY = #{param.oldvoky}
		AND UPDTCHK = #{param.updtchk}
